<?php
// ================================================================
//  portal/index.php  — Client Portal (Public, No Login Required)
//  URL: https://invcs.optms.co.in/portal?t=TOKEN
//
//  TOKEN format: base64(invoiceId + ':' + invoiceNumber)
//  e.g. btoa("81:INV-2026-002") = "ODE6SU5WLTIwMjYtMDAy"
//
//  No DB token table needed — the invoice ID is embedded in the
//  base64 token itself (generated by the frontend _portalURL fn).
// ================================================================

require_once __DIR__ . '/../config/db.php';

$rawToken = $_GET['t'] ?? '';
$error    = '';
$inv      = null;
$client   = [];
$payments = [];
$settings = [];
$invoiceId = 0;

if (!$rawToken) {
    $error = 'Invalid or missing link. Please ask your service provider for a valid invoice link.';
} else {
    // ── Detect token format ──────────────────────────────────────
    // Format A: 32-char lowercase hex  → random token stored in portal_tokens table
    //           e.g. "8bf863a1605406e45d14b80eebe5c846"
    // Format B: base64(id:invoiceNum)  → btoa token generated by frontend _portalURL()
    //           e.g. "ODE6SU5WLTIwMjYtMDAy" decodes to "81:INV-2026-002"

    if (preg_match('/^[0-9a-f]{32}$/', $rawToken)) {
        // ── Format A: hex token — look up in portal_tokens DB ────
        try {
            $db = getDB();

            // Auto-create table if needed
            $db->exec("CREATE TABLE IF NOT EXISTS `portal_tokens` (
                `id`          INT UNSIGNED NOT NULL AUTO_INCREMENT,
                `invoice_id`  INT UNSIGNED NOT NULL,
                `token`       VARCHAR(64)  NOT NULL,
                `views`       INT UNSIGNED NOT NULL DEFAULT 0,
                `last_viewed` DATETIME     NULL,
                `expires_at`  DATETIME     NULL,
                `created_at`  DATETIME     NOT NULL DEFAULT CURRENT_TIMESTAMP,
                PRIMARY KEY (`id`),
                UNIQUE KEY `uk_portal_invoice` (`invoice_id`),
                UNIQUE KEY `uk_portal_token`   (`token`)
            ) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4");

            $stmt = $db->prepare(
                'SELECT invoice_id FROM portal_tokens
                 WHERE token = :token
                   AND (expires_at IS NULL OR expires_at > NOW())
                 LIMIT 1'
            );
            $stmt->execute([':token' => $rawToken]);
            $row = $stmt->fetch(PDO::FETCH_ASSOC);
            if ($row) {
                $invoiceId = (int)$row['invoice_id'];
                // Bump view counter
                $db->prepare('UPDATE portal_tokens SET views = views + 1, last_viewed = NOW() WHERE token = :t')
                   ->execute([':t' => $rawToken]);
            } else {
                $error = 'This link is invalid or has expired. Please contact your service provider.';
            }
        } catch (Exception $e) {
            error_log('portal hex token lookup error: ' . $e->getMessage());
            $error = 'A server error occurred. Please try again later.';
        }

    } else {
        // ── Format B: base64(id:num) token — decode directly ─────
        $decoded = base64_decode(strtr($rawToken, '-_', '+/'), true);
        if ($decoded === false || strpos($decoded, ':') === false) {
            $error = 'Invalid link format. Please ask your service provider for a valid link.';
        } else {
            // "81:INV-2026-002" → invoice ID is the part before ':'
            $parts     = explode(':', $decoded, 2);
            $invoiceId = (int)$parts[0];
            if ($invoiceId <= 0) {
                $error = 'Invalid link. Invoice ID could not be determined.';
            }
        }
    }
}

if (!$error && $invoiceId > 0) {
    try {
        $db = getDB();

        // Fetch invoice — look up by id only (the number in the token is just for display)
        $stmt = $db->prepare("
            SELECT i.id AS invoice_id, i.invoice_number, i.issued_date AS issue_date,
                   i.due_date, i.grand_total AS amount, i.subtotal,
                   i.discount_pct, i.discount_amt, i.gst_amount,
                   i.status, i.client_id, i.service_type,
                   i.notes, i.terms, i.bank_details, i.currency
            FROM invoices i WHERE i.id = :id LIMIT 1
          ");
        $stmt->execute([':id' => $invoiceId]);
        $inv = $stmt->fetch(PDO::FETCH_ASSOC);

        if (!$inv) {
            $error = 'Invoice not found. The link may be outdated.';
        } else {
            // Client details
            $cStmt = $db->prepare(
                'SELECT name, email, phone, address FROM clients WHERE id = :id'
            );
            $cStmt->execute([':id' => $inv['client_id']]);
            $client = $cStmt->fetch(PDO::FETCH_ASSOC) ?: [];

            // Payment history
            $pStmt = $db->prepare(
                'SELECT amount, payment_date, method, transaction_id, notes
                 FROM payments WHERE invoice_id = :id ORDER BY payment_date ASC'
            );
            $pStmt->execute([':id' => $inv['invoice_id']]);
            $payments = $pStmt->fetchAll(PDO::FETCH_ASSOC);

            // Company settings
            try {
                $sRows = $db->query("SELECT `key`, value FROM settings")->fetchAll(PDO::FETCH_ASSOC);
                foreach ($sRows as $r) $settings[$r['key']] = $r['value'];
            } catch (Exception $e) { /* settings table might differ */ }
        }
    } catch (Exception $e) {
        error_log('portal/index.php error: ' . $e->getMessage());
        $error = 'A server error occurred. Please try again later.';
    }
}

// ── Helpers ──────────────────────────────────────────────────
function fmt_inr($n, $sym = '₹') {
    return $sym . number_format((float)$n, 2, '.', ',');
}
function status_col($s) {
    return match($s) {
        'Paid'      => '#388E3C',
        'Pending'   => '#F9A825',
        'Overdue'   => '#C62828',
        'Partial'   => '#E65100',
        'Draft'     => '#9E9E9E',
        'Cancelled' => '#757575',
        default     => '#888'
    };
}

$sym        = $inv['currency'] ?: '₹';
$totalAmt   = (float)($inv['amount']  ?? 0);
$totalPaid  = array_sum(array_column($payments, 'amount'));
$remaining  = max(0, $totalAmt - $totalPaid);
$pct        = $totalAmt > 0 ? min(100, round($totalPaid / $totalAmt * 100)) : 0;

$companyName    = $settings['company_name']    ?? 'OPTMS Tech';
$companyAddress = $settings['company_address'] ?? '';
$companyGST     = $settings['company_gst']     ?? '';
$companyEmail   = $settings['company_email']   ?? '';
$companyPhone   = $settings['company_phone']   ?? '';
$companyUPI     = $settings['company_upi']     ?? '';
$companyQR      = $settings['company_qr']      ?? '';
