<script>
function copyUPI() {
  const id  = document.getElementById('upiId')?.textContent?.trim();
  const btn = document.getElementById('copyBtn');
  if (!id) return;
  const done = () => {
    if (btn) { btn.innerHTML='<i class="fas fa-check"></i> Copied!'; btn.style.background='#388E3C'; }
    setTimeout(()=>{ if(btn){btn.innerHTML='<i class="fas fa-copy"></i> Copy';btn.style.background='';} }, 2000);
  };
  if (navigator.clipboard) {
    navigator.clipboard.writeText(id).then(done).catch(()=>fallback(id,done));
  } else { fallback(id,done); }
}
function fallback(text,cb) {
  const ta=document.createElement('textarea'); ta.value=text; ta.style.position='fixed'; ta.style.opacity='0';
  document.body.appendChild(ta); ta.focus(); ta.select(); try{document.execCommand('copy');}catch(e){}
  document.body.removeChild(ta); cb();
}
</script>
